// StrictServerInterface represents all server handlers.
type StrictServerInterface interface {
	// Health check
	// (GET /health)
	GetHealth(ctx context.Context, request GetHealthRequestObject) (GetHealthResponseObject, error)
	// Log in with email and password
	// (POST /login)
	PostAuthLogin(ctx context.Context, request PostAuthLoginRequestObject) (PostAuthLoginResponseObject, error)
	// Clear session cookie
	// (POST /logout)
	PostAuthLogout(ctx context.Context, request PostAuthLogoutRequestObject) (PostAuthLogoutResponseObject, error)
	// Return the currently authenticated user
	// (GET /me)
	GetAuthMe(ctx context.Context, request GetAuthMeRequestObject) (GetAuthMeResponseObject, error)
	// Register a new account
	// (POST /register)
	PostAuthRegister(ctx context.Context, request PostAuthRegisterRequestObject) (PostAuthRegisterResponseObject, error)
	// List all resumes for the authenticated user
	// (GET /resumes)
	GetResumes(ctx context.Context, request GetResumesRequestObject) (GetResumesResponseObject, error)
	// Create a new resume
	// (POST /resumes)
	PostResume(ctx context.Context, request PostResumeRequestObject) (PostResumeResponseObject, error)
	// Delete a resume (cascades to versions)
	// (DELETE /resumes/{id})
	DeleteResume(ctx context.Context, request DeleteResumeRequestObject) (DeleteResumeResponseObject, error)
	// Get a resume by ID
	// (GET /resumes/{id})
	GetResume(ctx context.Context, request GetResumeRequestObject) (GetResumeResponseObject, error)
	// Update resume data and template
	// (PATCH /resumes/{id})
	PatchResume(ctx context.Context, request PatchResumeRequestObject) (PatchResumeResponseObject, error)
	// Update only the resume title
	// (PATCH /resumes/{id}/title)
	PatchResumeTitle(ctx context.Context, request PatchResumeTitleRequestObject) (PatchResumeTitleResponseObject, error)
	// List version history for a resume
	// (GET /resumes/{id}/versions)
	GetResumeVersions(ctx context.Context, request GetResumeVersionsRequestObject) (GetResumeVersionsResponseObject, error)
	// Create a named (manual) version snapshot
	// (POST /resumes/{id}/versions)
	PostResumeVersion(ctx context.Context, request PostResumeVersionRequestObject) (PostResumeVersionResponseObject, error)
	// Get a specific version snapshot
	// (GET /resumes/{id}/versions/{vid})
	GetResumeVersion(ctx context.Context, request GetResumeVersionRequestObject) (GetResumeVersionResponseObject, error)
	// Restore a version snapshot as the current resume data
	// (POST /resumes/{id}/versions/{vid}/restore)
	PostResumeVersionRestore(ctx context.Context, request PostResumeVersionRestoreRequestObject) (PostResumeVersionRestoreResponseObject, error)
}

type StrictHandlerFunc func(ctx context.Context, w http.ResponseWriter, r *http.Request, request any) (any, error)
type StrictMiddlewareFunc func(f StrictHandlerFunc, operationID string) StrictHandlerFunc

type StrictHTTPServerOptions struct {
	RequestErrorHandlerFunc  func(w http.ResponseWriter, r *http.Request, err error)
	ResponseErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

func NewStrictHandler(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: StrictHTTPServerOptions{
		RequestErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		},
		ResponseErrorHandlerFunc: func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusInternalServerError)
		},
	}}
}

func NewStrictHandlerWithOptions(ssi StrictServerInterface, middlewares []StrictMiddlewareFunc, options StrictHTTPServerOptions) ServerInterface {
	return &strictHandler{ssi: ssi, middlewares: middlewares, options: options}
}

type strictHandler struct {
	ssi         StrictServerInterface
	middlewares []StrictMiddlewareFunc
	options     StrictHTTPServerOptions
}

// GetHealth operation middleware
func (sh *strictHandler) GetHealth(w http.ResponseWriter, r *http.Request) {
	var request GetHealthRequestObject

	handler := func(ctx context.Context, w http.ResponseWriter, r *http.Request, request interface{}) (interface{}, error) {
		return sh.ssi.GetHealth(ctx, request.(GetHealthRequestObject))
	}
	for _, middleware := range sh.middlewares {
		handler = middleware(handler, "GetHealth")
	}

	response, err := handler(r.Context(), w, r, request)

	if err != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, err)
	} else if validResponse, ok := response.(GetHealthResponseObject); ok {
		if err := validResponse.VisitGetHealthResponse(w); err != nil {
			sh.options.ResponseErrorHandlerFunc(w, r, err)
		}
	} else if response != nil {
		sh.options.ResponseErrorHandlerFunc(w, r, fmt.Errorf("unexpected response type: %T", response))
	}
}

